// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十六點三十五分。雨比三點鐘的時候又大了一層。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "裝卸區的水泥平台上積了一層薄水，工作人員的鞋底踩上去會發出「唧——唧——」的聲音，像踩在不斷恢復的傷口上。校務廂型車的後門大開著，車廂裡的燈亮著，冷白色的光照在一排已經被繩索固定的硬殼箱上。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從禮堂側門出來的時候，把志工背心的拉鏈拉到最高，領口翻進去遮住半截下巴，讓自己看起來和其他在雨裡跑來跑去搬東西的學生沒有任何區別。他走向裝卸區的時候，一個工作人員正好抱著一捆電纜從他身邊經過，差點撞到他。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.Staff, character: "工作人員", dialogue: "讓一下——哎，你，志工對吧？幫忙把那邊腳架袋搬到車上，快。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "好。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走過去，彎腰拎起那個裝著折疊腳架的長條帆布袋。袋子比他想的重，金屬管件在裡面互相撞擊，發出沉濁的噹啷聲。他抱著它走向車尾，沿著折疊鋁合金坡道走上去，把它放進車廂右側靠裡的位置。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)車廂。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)比我想的深。從車尾到駕駛室隔板大約三公尺，寬度不到兩公尺。右側已經堆了三排硬殼箱，左側靠門的位置放著藍色塑膠籃和電纜捲。中間的過道很窄，只能容一個人側身通過。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)人可以藏在右側箱子後面。如果我把箱子推回原位，從外面看不到裡面有人。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從車上跳下來，沒有多停留。接下來的二十分鐘裡，他成了裝卸區最不起眼的一雙手——搬電纜、搬硬碟箱、搬舞台布景包、搬直播用器材盒。每一趟他都從車尾走上去，把東西放到工作人員指定的位置，然後走下來，再去拿下一個。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有人問他是誰。沒有人核對他的名字。工作人員的注意力全部集中在「快」和「別淋雨」這兩件事上——雨越來越大，每樣東西搬出來都會在三秒內被淋濕表面，他們在跟水賽跑。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他們不看我。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這裡有六個工作人員，三個學生志工。三個志工裡，一個在搬燈光架，一個在搬音控台，一個是我。沒有人數過我們有幾個人。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果我少了一個，或者多了一個，沒有人會發現。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十七點十二分。林主任出現在平台上。他的西裝外套上套了一件透明雨衣，頭髮被風吹亂了，眼鏡片上全是水珠。他看了一眼手錶，又看了一眼車廂，嘴裡罵了一句聽不清的話，然後開始催人。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "快快快——硬碟箱裝了沒有？攝影組那邊到底拷完沒有？十七點四十必須出發，再晚管制點就過不去了！", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.Staff, character: "工作人員", dialogue: "裝了裝了，最後一箱。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "繩子拉緊——山路彎多，別到時候全砸了。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十七點十八分。裝卸接近尾聲。工作人員開始把最後幾箱設備塞進車廂右側的縫隙裡，用彈力繩和尼龍帶固定。車廂裡的空間越來越小，箱子疊了三層，最上面那層已經快碰到車頂。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)最後一趟。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他搬著一個標著「直播訊號備份」的扁平方形箱子上車。把它塞進右側最裡面的位置時，他的手指碰到了箱子堆後方的暗處——那裡有一個大約四十公分的縫隙，被前面的箱子遮得嚴嚴實實，從車尾往裡看完全看不到。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這裡。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果我鑽進這個縫隙，把前面的箱子推回原位，從外面看不到我。車廂裡沒有燈——不，有一盞，但在駕駛室隔板上方，光線照不到右側最裡面。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)司機不會進後車廂。他只需要啟動車，從側門開出去。工作人員裝完就會下車。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我只要在這裡不動。不動。不出聲。不咳嗽。不打噴嚏。直到車開出去。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從車尾跳下來，環顧了一圈。平台上的工作人員正在做最後的固定和檢查，林主任站在車頭旁邊打電話，聲音被雨聲蓋住了，只聽得到零碎的詞——「⋯⋯準備好了⋯⋯」「⋯⋯對，後山那邊⋯⋯」「⋯⋯收到通知就改⋯⋯」", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十七點二十二分。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)現在。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他假裝繞到車尾檢查箱子是否固定好。彎腰，雙手按在箱子上，推了推——然後在沒有任何人注意的那一秒，他的身體滑進了右側箱子堆後方的縫隙裡。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "膝蓋抵著冰涼的金屬車底板，背脊靠著車廂壁的冷鐵皮，左右兩側是硬殼箱的側面。他把自己壓縮成盡可能小的體積，蜷在箱子後面的黑暗裡，像一塊被塞進縫隙的行李。", background: Background.Chapter_2_Ch2_Act9_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要動。不要呼吸太大聲。不要想。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我已經進來了。", background: Background.Chapter_2_Ch2_Act9_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外面傳來工作人員的聲音。最後的箱子被推到位，彈力繩被拉緊時發出「嘎——嘎——」的聲音。有人在車尾拍了兩下車體。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Staff, character: "工作人員", dialogue: "好了！都固定了。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "關門。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "後門被推上來了。不是完全關死——鎖扣沒有卡到位，門留了一條大約兩公分的縫，外面的光線和水霧從縫裡擠進來，在車廂地面上畫出一條窄窄的亮線。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)門沒關死。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)兩公分的縫。不夠我從裡面推開逃出去，但能透氣，也能讓我聽到外面的聲音。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他透過箱子之間的縫隙，看到了那條光線。光線之外，是模糊的裝卸區——雨幕、走動的腿、反光背心的條紋、黑雨衣的下擺。一切都像透過磨砂玻璃在看，輪廓模糊，只有顏色和運動方向是清晰的。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "引擎發動了。整個車廂震動了一下，金屬壁板開始嗡嗡地共振，像一頭醒來的巨獸在低吼。空氣裡多了一股柴油和機油的味道，蓋過了塑膠箱和潮濕金屬原有的氣息。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)走了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)它要走了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)只要離開這座學校，今晚十點二十二分就只是鐘樓上的一場停電，和我無關。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後車沒有動。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯怎麼回事？", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "引擎在轉，但車沒有移動。透過後門的縫隙，他聽到了外面的對話——不是完整的句子，是被雨聲切割成碎片的詞語。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個聲音。年輕的。壓抑的。帶著力度的。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)韓越。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的心臟猛地收縮了一下。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "透過縫隙，他看到了。韓越站在車尾外面，離後門不到一公尺。他的頭髮被雨打濕了，貼在額頭上，整個人在雨裡顯得比平時更瘦、更硬。他的眼睛盯著車廂裡面——不是籠統地看，是在掃視，視線從左到右，從近到遠，像在找什麼具體的東西。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在看車廂。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在看——右側的箱子。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)箱子位置變了。我鑽進來的時候推動了最外層的箱子。和原來的位置差了大約十公分。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他看到了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的眉頭擠在一起。他往前走了半步，右手已經抬起來了——他要拉開後門，把頭探進來看。他的手指碰到了車門邊緣。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他打開門就會看到我。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言把自己往箱子後面又壓了兩公分。背脊抵著車廂壁，冰涼的鐵皮隔著校服布料貼上來，像一隻冰冷的手掌。他屏住了呼吸。整個世界只剩下心跳聲和雨聲。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的手指勾住了門邊緣。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後——", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Staff, character: "工作人員", dialogue: "韓越！你那邊好了沒？林主任叫你過去幫忙搬禮堂的東西，那邊缺人！", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的動作停住了。他的手指還勾在門邊緣上，停了一秒。兩秒。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的視線從車廂裡收回來，轉向聲音的方向。然後又轉回來，最後掃了一眼車廂深處——那個他看不清楚的、黑暗的、被箱子遮住大半的深處。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在看。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他知道裡面有什麼不對。箱子位置變了。但他不確定是什麼。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果他現在打開門——", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越鬆開了手指。他沒有打開門。他退後一步，站在雨裡，看著車廂深處看了最後一眼。他的嘴唇動了一下——不知道是罵了一句什麼，還是自言自語了什麼——然後他轉身，朝禮堂方向跑進了雨裡。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他走了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他沒有開門。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他看到了箱子位置不對。但他沒有開門確認。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)為什麼？", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果是他的東西在裡面——如果他在裝卸區碰過那個箱子、放過什麼——他應該會打開門確認它還在。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他沒有。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在裝卸區開箱子，不是在往車上放東西。他在確認什麼。確認完了，他就走了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)——他不是在找我。他甚至不確定裡面有沒有人。他只是看到了箱子位置不對，本能地想確認，然後被人叫走了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)或者他看到了我，但選擇不揭穿。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不知道。不想了。車要走了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車動了。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一陣低沉的震動從底盤傳上來，穿過他的膝蓋、脊椎、牙齒。車廂搖晃了一下，然後開始緩慢地向前移動。透過後門的縫隙，裝卸區的平台開始往後退——水泥欄杆、雨棚邊緣的水簾、堆在角落的空箱子——一幅一幅地滑過去，像被人抽走的幻燈片。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)走了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我在離開。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車廂搖晃著。裝卸區消失了。側門的鐵柵欄打開又合上的聲音傳進來，金屬碰撞的巨響在密閉空間裡被放大了三倍。然後車速加快了，路面的震動變得更密集，雨水從後門的縫隙裡飛進來，在黑暗中畫出一條條銀色的細線。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我離開學校了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)二十二點二十二分。鐘樓。停電。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)和我無關了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他允許自己呼吸了。深吸一口——柴油味、塑膠味、潮濕金屬味、雨水的腥味——全部混在一起，不好聞，但真實。這是真實的空氣。他活著。他在離開。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車在轉彎。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是山路的第一個彎。離心力把他的身體往左推了一下，膝蓋撞在硬殼箱的邊角上，痛感尖銳但短暫。車廂右側的箱子堆跟著傾斜——最上面那層滑了一下，彈力繩發出繃緊的嘎吱聲。有什麼東西從箱子堆頂上滑下來，砸在他左邊的地板上，發出一聲悶響。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車又轉了一個彎。更急。右側的箱子堆再次傾斜，這次更厲害——中層的一個箱子被擠開了，和旁邊的箱子之間露出了一條大約二十公分的縫。縫隙的後面，是車廂最深處的角落，之前被箱子完全遮住、他上車時沒有看到的角落。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑暗裡，那個角落裡有一樣東西。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色的。方形的。比其他的硬殼箱小。大約三十公分長，二十公分寬，表面是磨砂的硬質尼龍面料。邊角有磨損，拉鏈是金屬的，在車廂的微光裡反了一下光。它的形狀——", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)相機包。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是一個相機包。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是裝攝影機的大箱，不是裝硬碟的防震盒，是一個——單個——相機——的——包。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)相機包。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)訊息裡說的——「相機」。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這車上有相機。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的眼睛在黑暗裡慢慢適應了。車廂深處的那個角落，借著後門縫隙漏進來的一線灰光，他看清了更多細節——相機包的正面貼著一張標籤。標籤是手寫的，黑色馬克筆，字跡有些模糊，像是被蹭過。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)標籤。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)上面寫——", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「攝影組備份」。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)攝影組備份。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)和外面那些箱子的標籤一樣。和我在裝卸區看到的箱子一模一樣的標籤。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但那些箱子上寫的是「攝影組備份箱」「直播訊號備份」。這個包上只寫了「攝影組備份」四個字。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)備份。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)備份的是什麼？", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)相機。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)訊息裡說的——「不要把相機交給任何大人」——「相機」——", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這個包裡有相機。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)或者有和相機有關的東西。記憶卡。照片。證據。任何東西。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)而我在和它同一輛車上。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "冷。從脊椎開始，像一條冰蛇沿著脊柱往上爬，爬過後頸，爬到頭皮，整個頭皮發麻。他的手指在黑暗裡收緊，指甲掐進掌心的肉裡，痛感是唯一能確認他還清醒的東西。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我要下車。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我要下車。現在。立刻。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他撐起身體，膝蓋撞在箱子上，手指摸向後門的方向——", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車又轉了一個彎。更急。他的身體被甩回箱子堆裡，肩膀撞在硬殼箱的邊角上，一陣刺痛從鎖骨傳到指尖。外面的景色透過縫隙飛速後退——不是裝卸區的水泥平台了，是山路。盤山公路。兩側是模糊的樹影和雨幕，路面在車燈裡泛著水光。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)已經在山路上了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)車已經離開裝卸區了。我在車裡。車在走。門從裡面推不開——鎖扣是從外面扣的。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我下不去了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠回車廂壁上。後腦勺抵著冰涼的鐵皮，震動從金屬裡傳進頭骨，嗡嗡的，持續的，像一把不斷被撥動的琴弦。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我以為我找到的是出口。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我躲進了一輛裝著直播備份器材的校務車。我只看到了硬殼箱和硬碟盒。沒有看到相機包。它藏在車廂最裡面，被前面的箱子擋得嚴嚴實實。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果車沒有轉彎，如果箱子沒有滑開，我不會看到它。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但它在那裡。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)從一開始就在那裡。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我以為自己坐上了出口。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)出口裡藏著訊息裡最危險的東西。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車繼續在山路上行駛。雨聲從車外灌進來，被金屬車廂放大成持續的轟鳴，像被困在一面鼓的內部。偶爾有一道閃電劈開天幕，白光從縫隙裡射進來，照亮整個車廂零點幾秒——黑色的箱子、銀色的金屬扣、深處那個沉默的相機包——然後黑暗再次合攏。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要動。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要碰那個包。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要讓任何人知道我在這裡。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)也許——也許這個包是空的。也許它只是被隨手放在這裡的備用包。也許「攝影組備份」就是字面意思，裡面裝的是電池和充電器。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)也許。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但韓越在裝卸區開箱子。他打開箱子，看了一眼，合上了。動作很快。像在確認什麼東西在不在。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在確認的就是這個包。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他確認完了。包在車上。車出發了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在車快關門的時候走過來，看到箱子位置不對——他不是在找我。他⋯⋯是在確認這個包？", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)包在車上。車在走。我在車上。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)和這個包一起。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "山路在繼續。車廂在搖晃。雨水從後門的縫隙裡不斷飛進來，在他的校服膝蓋上積成一小片深色的水漬。他的牙齒開始打顫——不是冷，至少不全是冷。是某種更深層的、從骨頭裡往外滲的顫慄。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)二十二點二十二分。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我離開了學校。我在山路上。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但訊息裡那個詞——「相機」——它不在我身後的學校裡了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)它在我身邊。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)它和我同一輛車。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車拐進了一個更窄的彎道。引擎的聲音變了——從勻速的低吼變成吃力的嘶鳴，像一個人在爬陡坡。路面的震動變得不規律，底盤偶爾磕到什麼東西，發出沉悶的金屬撞擊聲。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯路變了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這不是早上車輛表上標的主山路。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)主山路是雙車道柏油路，路面平。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這條路更窄。更顛。像碎石路面。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)後山維修路。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)林主任說的那條路。「必要時走後山維修路。」", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)「必要時」的指令下來了。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠在車廂壁上，聽著引擎的嘶鳴和碎石敲打底盤的聲音。透過後門的縫隙，他看到的不再是雙車道柏油路面，而是一條更窄的、兩側被灌木和碎石擠壓的維修便道。路的左側是山坡，右側是——黑暗。看不到邊際的黑暗。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這條路沒有路燈。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這條路沒有監視器。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)林主任把這輛車導到了一條沒有監視器的路上。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車繼續往前。雨沒有停。黑暗裡，那個黑色的相機包安靜地躺在車廂最深處的角落，標籤朝上，四個字在每一次閃電的白光裡短暫地清晰——", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "攝影組備份。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後黑暗再次合攏。什麼都看不見了。只有車廂的震動、引擎的嘶鳴、雨水打在金屬車頂上的鼓點，以及他自己的心跳聲——在密閉的黑暗裡，大得像在胸腔裡敲鼓。", background: Background.Chapter_2_Ch2_Act9_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我逃不掉的。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我以為我找到了出口。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但出口本身就是陷阱。", background: Background.Chapter_2_Ch2_Act9_S1, portrait: Portrait.GuYan_Trembling },
];
